import React, { useState, useEffect } from 'react';
import { User, Mail, Shield, Key, Camera, LogOut } from 'lucide-react';
import { setAuthToken } from '../services/api';
import { useNavigate } from 'react-router-dom';

export default function Profile() {
    const navigate = useNavigate();
    const [isEditing, setIsEditing] = useState(false);

    // Password Modal State
    const [isPasswordModalOpen, setIsPasswordModalOpen] = useState(false);
    const [passwords, setPasswords] = useState({ current: '', new: '', confirm: '' });
    const [passwordError, setPasswordError] = useState('');
    const [passwordSuccess, setPasswordSuccess] = useState('');

    // Using placeholder data since we don't have a GET /me endpoint yet
    const [profile, setProfile] = useState({
        name: 'VidyaMitra User',
        email: 'user@example.com',
        role: 'Job Seeker',
        phone: '+1 (555) 000-0000',
        location: 'San Francisco, CA'
    });

    // Load profile from local storage on component mount
    useEffect(() => {
        const savedProfile = localStorage.getItem('vidyamitra_user_profile');
        if (savedProfile) {
            try {
                setProfile(JSON.parse(savedProfile));
            } catch (e) {
                console.error("Could not parse saved profile data", e);
            }
        }
    }, []);

    const handleSaveProfile = () => {
        if (isEditing) {
            // About to toggle off, save to local storage
            localStorage.setItem('vidyamitra_user_profile', JSON.stringify(profile));
        }
        setIsEditing(!isEditing);
    };

    const handleLogout = () => {
        setAuthToken(null);
        navigate('/');
    };

    const handleChangePassword = (e) => {
        e.preventDefault();
        setPasswordError('');
        setPasswordSuccess('');

        if (passwords.new !== passwords.confirm) {
            setPasswordError("New passwords don't match");
            return;
        }
        if (passwords.new.length < 6) {
            setPasswordError("Password must be at least 6 characters");
            return;
        }

        // Mock successful password change
        setPasswordSuccess("Password updated successfully!");
        setTimeout(() => {
            setIsPasswordModalOpen(false);
            setPasswords({ current: '', new: '', confirm: '' });
            setPasswordSuccess('');
        }, 1500);
    };

    return (
        <div className="max-w-4xl space-y-8">
            {/* Header Profile Card */}
            <div className="glass-panel p-8 rounded-3xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-r from-primary-500 to-indigo-600"></div>

                <div className="relative pt-16 sm:pt-20 flex flex-col sm:flex-row items-center sm:items-end gap-6">
                    <div className="relative group">
                        <button
                            className="w-32 h-32 rounded-full border-4 border-white bg-slate-100 shadow-xl overflow-hidden flex items-center justify-center bg-gradient-to-tr from-primary-100 to-indigo-100 hover:scale-105 transition-transform"
                            onClick={() => alert('Profile picture upload clicked')}
                        >
                            <span className="text-5xl font-black text-indigo-400">U</span>
                        </button>
                        <button
                            className="absolute bottom-2 right-2 p-2 bg-white rounded-full shadow-md text-slate-600 hover:text-primary-600 transition opacity-0 group-hover:opacity-100 pointer-events-none"
                        >
                            <Camera className="w-4 h-4" />
                        </button>
                    </div>

                    <div className="flex-1 text-center sm:text-left">
                        <h2 className="text-3xl font-extrabold text-slate-900">{profile.name}</h2>
                        <p className="text-slate-500 font-medium">{profile.role} ΓÇó {profile.location}</p>
                    </div>

                    <div className="flex gap-3">
                        <button
                            onClick={handleSaveProfile}
                            className="px-6 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-xl font-semibold shadow-sm hover:bg-slate-50 transition"
                        >
                            {isEditing ? 'Save Changes' : 'Edit Profile'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Profile Details Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

                {/* Personal Information */}
                <div className="md:col-span-2 glass-panel p-8 rounded-3xl space-y-6">
                    <h3 className="text-xl font-bold text-slate-800 border-b border-slate-100 pb-4">Personal Information</h3>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Full Name</label>
                            {isEditing ? (
                                <input type="text" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.name} onChange={e => setProfile({ ...profile, name: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.name}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Email Address</label>
                            {isEditing ? (
                                <input type="email" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.email} onChange={e => setProfile({ ...profile, email: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800 flex items-center gap-2"><Mail className="w-4 h-4 text-slate-400" /> {profile.email}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Phone</label>
                            {isEditing ? (
                                <input type="tel" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.phone} onChange={e => setProfile({ ...profile, phone: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.phone}</p>
                            )}
                        </div>
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Location</label>
                            {isEditing ? (
                                <input type="text" className="w-full p-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-primary-500 transition" value={profile.location} onChange={e => setProfile({ ...profile, location: e.target.value })} />
                            ) : (
                                <p className="font-semibold text-slate-800">{profile.location}</p>
                            )}
                        </div>
                    </div>
                </div>

                {/* Security Settings */}
                <div className="glass-panel p-8 rounded-3xl space-y-6">
                    <h3 className="text-xl font-bold text-slate-800 border-b border-slate-100 pb-4">Security</h3>

                    <button
                        onClick={() => setIsPasswordModalOpen(true)}
                        className="w-full flex items-center justify-between p-4 rounded-xl border border-slate-200 hover:border-primary-300 hover:shadow-md transition group bg-white cursor-pointer"
                    >
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-slate-50 rounded-lg group-hover:bg-primary-50 text-slate-600 group-hover:text-primary-600 transition">
                                <Key className="w-5 h-5" />
                            </div>
                            <div className="text-left">
                                <p className="font-bold text-slate-800 text-sm">Change Password</p>
                                <p className="text-xs text-slate-500">Update your credentials</p>
                            </div>
                        </div>
                    </button>

                    {/* Two-Factor Auth Removed as Per Request */}

                    <div className="pt-6 mt-6 border-t border-slate-100">
                        <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-red-50 text-red-600 rounded-xl font-bold hover:bg-red-100 hover:shadow-sm transition">
                            <LogOut className="w-5 h-5" /> Sign Out from Account
                        </button>
                    </div>
                </div>

            </div>

            {/* Password Change Modal Overlay */}
            {isPasswordModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4">
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        className="bg-white rounded-3xl shadow-2xl max-w-md w-full p-8 border border-slate-100"
                    >
                        <h3 className="text-2xl font-bold text-slate-800 mb-6 flex items-center gap-2">
                            <Key className="w-6 h-6 text-primary-500" />
                            Change Password
                        </h3>

                        {passwordError && <p className="text-red-500 text-sm mb-4 p-3 bg-red-50 rounded-lg border border-red-100">{passwordError}</p>}
                        {passwordSuccess && <p className="text-green-600 text-sm mb-4 p-3 bg-green-50 rounded-lg border border-green-100 font-medium">{passwordSuccess}</p>}

                        <form onSubmit={handleChangePassword} className="space-y-4">
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">Current Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.current}
                                    onChange={e => setPasswords({ ...passwords, current: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">New Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.new}
                                    onChange={e => setPasswords({ ...passwords, new: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-semibold text-slate-700 mb-1">Confirm New Password</label>
                                <input
                                    type="password" required
                                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 bg-slate-50 transition"
                                    value={passwords.confirm}
                                    onChange={e => setPasswords({ ...passwords, confirm: e.target.value })}
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button
                                    type="button"
                                    onClick={() => {
                                        setIsPasswordModalOpen(false);
                                        setPasswords({ current: '', new: '', confirm: '' });
                                        setPasswordError('');
                                    }}
                                    className="flex-1 px-4 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-semibold hover:bg-slate-50 transition"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 px-4 py-3 bg-primary-600 text-white rounded-xl font-semibold shadow-md hover:bg-primary-700 transition"
                                >
                                    Update Password
                                </button>
                            </div>
                        </form>
                    </motion.div>
                </div>
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import {
    BarChart3,
    FileText,
    Briefcase,
    CheckCircle,
    Video,
    LogOut,
    BookOpen,
    User,
    Menu,
    X
} from 'lucide-react';

import ResumeAnalyzer from '../components/ResumeAnalyzer';
import SkillGapAnalysis from '../components/SkillGapAnalysis';
import CareerPath from '../components/CareerPath';
import Quiz from '../components/Quiz';
import Training from '../components/Training';
import Profile from '../components/Profile';

export default function Dashboard() {
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('overview');
    const [progressStats, setProgressStats] = useState({ resumeScore: '--', lastQuizScore: '--' });
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    useEffect(() => {
        if (activeTab === 'overview') {
            api.get('/progress/')
                .then(res => {
                    const records = res.data.records || [];
                    let resume = '--';
                    let quiz = '--';
                    records.forEach(r => {
                        if (r.module_name === 'Resume Score') resume = r.score;
                        if (r.module_name === 'Last Quiz Score') quiz = r.score;
                    });
                    setProgressStats({ resumeScore: resume, lastQuizScore: quiz });
                })
                .catch(err => console.error("Failed to load progress:", err));
        }
    }, [activeTab]);

    const handleLogout = () => {
        setAuthToken(null);
        navigate('/');
    };

    const navItems = [
        { id: 'overview', icon: BarChart3, label: 'Overview' },
        { id: 'resume', icon: FileText, label: 'Resume AI' },
        { id: 'skills', icon: Briefcase, label: 'Skill Gap' },
        { id: 'path', icon: CheckCircle, label: 'Career Path' },
        { id: 'quiz', icon: BookOpen, label: 'Quizzes & Training' },
        { id: 'profile', icon: User, label: 'Profile Settings' },
    ];

    return (
        <div className="min-h-screen bg-slate-50 flex overflow-hidden">
            {/* Mobile Sidebar Overlay */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-slate-900/50 z-40 md:hidden backdrop-blur-sm"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}

            {/* Sidebar Navigation */}
            <motion.aside
                initial={{ x: -250 }}
                animate={{ x: 0 }}
                className={`fixed md:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 flex flex-col transform transition-transform duration-300 ease-in-out ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
            >
                <div className="h-20 flex items-center px-8 border-b border-slate-100">
                    <h2 className="text-2xl font-bold text-slate-800">
                        Vidya<span className="text-primary-600">Mitra</span>
                    </h2>
                </div>

                <nav className="flex-1 py-8 px-4 space-y-2 overflow-y-auto">
                    {navItems.map((item) => (
                        <button
                            key={item.id}
                            onClick={() => {
                                setActiveTab(item.id);
                                setIsMobileMenuOpen(false);
                            }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition ${activeTab === item.id
                                ? 'bg-primary-50 text-primary-600 font-semibold shadow-sm'
                                : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900 font-medium'
                                }`}
                        >
                            <item.icon className="w-5 h-5" />
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-200">
                    <button
                        onClick={handleLogout}
                        className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-slate-600 hover:bg-red-50 hover:text-red-600 font-medium transition"
                    >
                        <LogOut className="w-5 h-5" />
                        Sign Out
                    </button>
                </div>
            </motion.aside>

            {/* Main Content Area */}
            <main className="flex-1 overflow-y-auto w-full relative">
                <div className="absolute top-0 right-0 w-96 h-96 bg-primary-100 rounded-full blur-3xl opacity-40 -z-10 animate-pulse-slow"></div>
                <div className="p-8 pb-20">

                    {/* Header */}
                    <header className="flex justify-between items-center mb-10">
                        <div>
                            <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">
                                {navItems.find(i => i.id === activeTab)?.label}
                            </h1>
                            <p className="text-slate-500 mt-1 placeholder">Welcome back to your career hub.</p>
                        </div>

                        <div className="flex items-center gap-4">
                            <button
                                className="md:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition mr-2"
                                onClick={() => setIsMobileMenuOpen(true)}
                            >
                                <Menu className="w-6 h-6" />
                            </button>
                            {/* User Avatar / Header Actions */}
                            <button
                                onClick={() => setActiveTab('profile')}
                                className="w-10 h-10 rounded-full bg-gradient-to-tr from-primary-500 to-indigo-500 flex items-center justify-center text-white font-bold shadow-md hover:shadow-lg transition transform hover:scale-105"
                                title="My Profile"
                            >
                                U
                            </button>
                            <button
                                onClick={handleLogout}
                                className="md:hidden p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full transition"
                                title="Sign Out"
                            >
                                <LogOut className="w-5 h-5" />
                            </button>
                        </div>
                    </header>

                    {/* Dynamic Content Mapping */}
                    <motion.div
                        key={activeTab}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.3 }}
                    >
                        {activeTab === 'overview' && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                {/* Dynamic Stats */}
                                {['Resume Score', 'Last Quiz Score'].map((stat, i) => {
                                    const value = i === 0 ? progressStats.resumeScore : progressStats.lastQuizScore;
                                    // Resume is out of 100, Quiz is out of 5
                                    const maxScore = i === 0 ? 100 : 5;
                                    const widthPct = value !== '--' ? Math.min(100, Math.round((value / maxScore) * 100)) : 0;

                                    return (
                                        <div key={i} className="glass-panel p-6 rounded-2xl hover:shadow-2xl transition transform hover:-translate-y-1">
                                            <h3 className="text-slate-500 font-medium">{stat}</h3>
                                            <div className="text-4xl font-extrabold text-slate-800 mt-2">
                                                {value}
                                                <span className="text-xl text-slate-400 font-medium">/{maxScore}</span>
                                            </div>
                                            <div className="mt-4 h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                                                <div className="h-full bg-primary-500 rounded-full transition-all duration-1000" style={{ width: `${widthPct}%` }}></div>
                                            </div>
                                        </div>
                                    );
                                })}

                                {/* Recent Activity */}
                                <div className="md:col-span-3 glass-panel p-6 rounded-2xl mt-4">
                                    <h3 className="text-xl font-bold text-slate-800 mb-4">Recent Milestones</h3>
                                    <ul className="space-y-4">
                                        <li className="flex items-center gap-4 text-slate-600 bg-white/50 p-3 rounded-xl border border-white">
                                            <CheckCircle className="w-5 h-5 text-slate-300" />
                                            No recent activity. Start by uploading your resume or taking a quiz!
                                        </li>
                                    </ul>
                                </div>
                            </div>
                        )}

                        {activeTab === 'resume' && (
                            <div className="animate-fade-in">
                                <ResumeAnalyzer />
                            </div>
                        )}

                        {activeTab === 'skills' && (
                            <div className="animate-fade-in">
                                <SkillGapAnalysis />
                            </div>
                        )}

                        {activeTab === 'path' && (
                            <div className="animate-fade-in">
                                <CareerPath />
                            </div>
                        )}

                        {activeTab === 'quiz' && (
                            <div className="animate-fade-in space-y-8">
                                <Quiz />
                                <div className="mt-8 pt-8 border-t border-slate-200">
                                    <Training />
                                </div>
                            </div>
                        )}

                        {activeTab === 'profile' && (
                            <div className="animate-fade-in">
                                <Profile />
                            </div>
                        )}

                    </motion.div>
                </div>
            </main>
        </div>
    );
}

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import { Mail, Lock, ArrowRight, Loader2 } from 'lucide-react';

export default function Login() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const res = await api.post('/auth/login', { email, password });
            setAuthToken(res.data.access_token);
            // Try to load any existing profile
            let storedProfileStr = localStorage.getItem('vidyamitra_user_profile');
            let storedProfile = storedProfileStr ? JSON.parse(storedProfileStr) : null;

            // Check if there is an existing seeded profile, if not, create a baseline
            if (!storedProfile) {
                storedProfile = {
                    name: 'VidyaMitra User',
                    role: 'Job Seeker',
                    phone: 'Add your phone number',
                    location: 'Add your location'
                };
            }

            // Force the email to match the login credentials as source of truth
            storedProfile.email = email;
            localStorage.setItem('vidyamitra_user_profile', JSON.stringify(storedProfile));
            navigate('/dashboard');
        } catch (err) {
            setError(err.response?.data?.detail || 'Failed to login');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center pt-16 px-4 relative">
            <div className="absolute top-1/4 left-1/4 w-72 h-72 bg-primary-300 rounded-full blur-3xl opacity-30 animate-pulse-slow"></div>

            <motion.div
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                className="glass-panel w-full max-w-md p-8 rounded-2xl relative z-10"
            >
                <div className="text-center mb-8">
                    <h2 className="text-3xl font-extrabold text-slate-900 mb-2">Welcome Back</h2>
                    <p className="text-slate-500">Log in to continue your career journey</p>
                </div>

                {error && (
                    <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm mb-6 text-center shadow-inner">
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} className="space-y-6">
                    <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700 ml-1">Email Address</label>
                        <div className="relative">
                            <Mail className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="email"
                                required
                                className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition bg-white/50"
                                placeholder="you@example.com"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                            />
                        </div>
                    </div>

                    <div className="space-y-1">
                        <label className="text-sm font-medium text-slate-700 ml-1">Password</label>
                        <div className="relative">
                            <Lock className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input
                                type="password"
                                required
                                className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition bg-white/50"
                                placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full flex items-center justify-center gap-2 bg-gradient-to-r from-primary-600 to-primary-500 text-white py-3 rounded-xl font-semibold shadow-lg hover:shadow-xl transition transform hover:-translate-y-0.5 disabled:opacity-70 disabled:transform-none"
                    >
                        {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : (
                            <>
                                Sign In <ArrowRight className="w-5 h-5" />
                            </>
                        )}
                    </button>
                </form>

                <p className="mt-6 text-center text-sm text-slate-600">
                    Don't have an account? <Link to="/register" className="text-primary-600 hover:text-primary-700 font-semibold transition">Register here</Link>
                </p>
            </motion.div>
        </div>
    );
}
